const { parseDuration } = require('./src/core/duration.js');

const cases = [
  ['30s', 30000],
  ['1h30m', 5400000],
  ['500ms', 500],
  ['250', 250],
  ['1h', 3600000],
  ['2d', 172800000],
  ['1h30m15s', 5415000],
  ['1000ms', 1000],
];

let pass = 0, fail = 0;
for (const [input, expected] of cases) {
  const result = parseDuration(input);
  if (result === expected) {
    console.log('PASS', input, '->', result);
    pass++;
  } else {
    console.log('FAIL', input, '-> got', result, 'expected', expected);
    fail++;
  }
}

// test throws
try { parseDuration('bad'); console.log('FAIL: should have thrown for \"bad\"'); fail++; } catch (e) { console.log('PASS throws on \"bad\"'); pass++; }
try { parseDuration('1x'); console.log('FAIL: should have thrown for \"1x\"'); fail++; } catch (e) { console.log('PASS throws on \"1x\"'); pass++; }
try { parseDuration('1h_bad'); console.log('FAIL: should have thrown for \"1h_bad\"'); fail++; } catch (e) { console.log('PASS throws on \"1h_bad\"'); pass++; }

console.log(pass + ' passed, ' + fail + ' failed');
